// Доступ к имени рабочего процесса осуществляется через _workflow.name
const workflow_name = $workflow.name;

// Ожидаем имя типа "DB_Initializer_Schema_HR"

// Есть ли в имени суффикс
const parsing = workflow_name.split('_');
if (parsing.length < 2) {
  throw new Error("Не указана схема для пользователя в названии процесса.");
}

const schema_name = parsing[1];

return [{ json: { scheme_name: schema_name } }];

// Получаем элементы из предыдущей ноды с кампаниями
const items = $input.all();

// Формируем массив инлайн-кнопок
const keyboard = items.map(item => {
  const name = item.json.campaign_name;
  const platform = item.json.advertising_platform; // Источник
  const id = item.json.campaign_id; // ID кампании

  return [
    {
      // Текст кнопки: "Название (Источник)"
      "text": `📈 ${name} (${platform})`,          
      // Колбэк: "cmpid-[ID]"
      "callback_data": `cmpid-${id}`
    }
  ];
});

// Возвращаем готовую структуру для отправки
return {
  json: {
    text: "Выберите кампанию:",
    reply_markup: {
      inline_keyboard: keyboard
    }
  }
};

